import type { Metadata } from "next";
import "./globals.css";
import tokens from "../../tokens.json";

export const metadata: Metadata = {
  title: "Everest Tours",
  description: "Premium small-group treks and cultural tours from Kathmandu."
};

// Design tokens (colors, fonts) come from tokens.json — generated by
// `blueprint tokens <slug>` from the donor, or the template default. We inject them
// as :root CSS custom properties so the whole site reads from one source of truth
// and changing a token value visibly changes the render.
function tokenCssVars(): string {
  const c = tokens.colors;
  const f = tokens.fonts;
  return `:root{--color-background:${c.background};--color-foreground:${c.foreground};--color-primary:${c.primary};--color-accent:${c.accent};--color-muted:${c.muted};--color-surface:${c.surface};--color-surface-dark:${c.surfaceDark};--color-ink:${c.ink};--font-heading:${f.heading.stack};--font-body:${f.body.stack};}`;
}

export default function RootLayout({
  children
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <head>
        <style dangerouslySetInnerHTML={{ __html: tokenCssVars() }} />
      </head>
      <body>{children}</body>
    </html>
  );
}
